PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE questions (
      game_key TEXT NOT NULL,
      source_uid INTEGER NOT NULL,
      category_id INTEGER NOT NULL,
      lang TEXT NOT NULL,
      region TEXT NOT NULL,
      sentence TEXT NOT NULL,
      PRIMARY KEY (game_key, source_uid, category_id, lang, region)
    ) WITHOUT ROWID;
CREATE TABLE tpf_questions (
      source_uid INTEGER NOT NULL,
      category_id INTEGER NOT NULL,
      lang TEXT NOT NULL,
      region TEXT NOT NULL,
      choice1 TEXT NOT NULL,
      choice2 TEXT NOT NULL,
      PRIMARY KEY (source_uid, category_id, lang, region)
    ) WITHOUT ROWID;
CREATE TABLE quiz_questions (
      source_uid INTEGER NOT NULL,
      category_id INTEGER NOT NULL,
      lang TEXT NOT NULL,
      region TEXT NOT NULL,
      sentence TEXT NOT NULL,
      options_json TEXT NOT NULL,
      PRIMARY KEY (source_uid, category_id, lang, region)
    ) WITHOUT ROWID;
CREATE TABLE team_battle_questions (
      source_uid INTEGER NOT NULL,
      mode TEXT NOT NULL,
      category_id INTEGER NOT NULL,
      lang TEXT NOT NULL,
      region TEXT NOT NULL,
      sentence TEXT NOT NULL,
      PRIMARY KEY (source_uid, mode, lang, region)
    ) WITHOUT ROWID;
CREATE TABLE dormelles_questions (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      lang TEXT NOT NULL,
      region TEXT NOT NULL,
      card_id INTEGER NOT NULL,
      category_id INTEGER NOT NULL,
      sentence TEXT NOT NULL
    );
CREATE TABLE imposter_words (
      pack_id TEXT NOT NULL,
      source_uid INTEGER NOT NULL,
      lang TEXT NOT NULL,
      region TEXT NOT NULL,
      word TEXT NOT NULL,
      imposter_hint_word TEXT NOT NULL,
      PRIMARY KEY (pack_id, source_uid, lang, region)
    ) WITHOUT ROWID;
PRAGMA writable_schema=ON;
CREATE TABLE IF NOT EXISTS sqlite_sequence(name,seq);
DELETE FROM sqlite_sequence;
CREATE INDEX questions_lookup ON questions (game_key, category_id, lang, region);
CREATE INDEX tpf_questions_lookup ON tpf_questions (category_id, lang, region);
CREATE INDEX quiz_questions_lookup ON quiz_questions (category_id, lang, region);
CREATE INDEX team_battle_questions_lookup ON team_battle_questions (mode, lang, region);
CREATE INDEX dormelles_questions_lookup ON dormelles_questions (lang, card_id, category_id, region);
CREATE INDEX imposter_words_lookup ON imposter_words (pack_id, lang, region);
PRAGMA writable_schema=OFF;
COMMIT;
